use actix_web::{web, App, HttpServer, HttpResponse, Result, http::header, fs::NamedFile};
use std::path::{Path, PathBuf};

async fn serve_file(path: web::Path<String>) -> Result<HttpResponse> {
    let filename = path.into_inner();
    
    // Prevent path traversal
    if filename.contains("..") || filename.starts_with('/') {
        return Ok(HttpResponse::BadRequest().finish());
    }
    
    let upload_dir = Path::new("uploads");
    let file_path = upload_dir.join(&filename);
    
    // Ensure the file is within the uploads directory
    if !file_path.starts_with(upload_dir) {
        return Ok(HttpResponse::BadRequest().finish());
    }
    
    match NamedFile::open(file_path) {
        Ok(named_file) => {
            let response = named_file
                .use_last_modified(true)
                .into_response(&web::HttpRequest::default());
            Ok(response)
        }
        Err(_) => Ok(HttpResponse::NotFound().finish()),
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/{filename}", web::get().to(serve_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}